export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

"use client";

import { useState, useCallback } from "react";
import type { BeadId, BeadType, BeadState } from "@/types/bead";

// ── Bead type defaults ───────────────────────────────────────────────────────

export interface BeadTypeConfig {
  radius: number;
  color: string;
}

export const BEAD_TYPE_DEFAULTS: Record<BeadType, BeadTypeConfig> = {
  wood: { radius: 0.2, color: "#D4A574" },
  silicone: { radius: 0.18, color: "#FF6B9D" },
  knit: { radius: 0.22, color: "#E8D5B7" },
  plastic: { radius: 0.19, color: "#6EC1E4" },
};

// ── Default chain ────────────────────────────────────────────────────────────

const DEFAULT_BEADS: BeadState[] = [
  { id: "bead-1", type: "wood", radius: 0.2, color: "#D4A574" },
  { id: "bead-2", type: "silicone", radius: 0.18, color: "#FF6B9D" },
  { id: "bead-3", type: "wood", radius: 0.22, color: "#C4956A" },
  { id: "bead-4", type: "plastic", radius: 0.19, color: "#6EC1E4" },
  { id: "bead-5", type: "wood", radius: 0.21, color: "#B8860B" },
  { id: "bead-6", type: "silicone", radius: 0.17, color: "#E8A0BF" },
  { id: "bead-7", type: "wood", radius: 0.2, color: "#DEB887" },
];

/** Cycle through bead types for variety when adding. */
const ADD_CYCLE: BeadType[] = ["wood", "silicone", "plastic", "knit"];
let addCounter = 0;

// ── Hook ─────────────────────────────────────────────────────────────────────

export interface UseBeadChainReturn {
  beads: BeadState[];
  addBead: (type?: BeadType) => void;
  removeBead: (id: BeadId) => void;
  removeLast: () => void;
  reset: () => void;
}

/**
 * Manages the bead chain state: array of BeadState with add/remove/reset.
 *
 * This is the primary state interface for the chain — downstream slices (S03)
 * will extend this with selection, reordering, and property editing.
 */
export function useBeadChain(): UseBeadChainReturn {
  const [beads, setBeads] = useState<BeadState[]>(DEFAULT_BEADS);

  const addBead = useCallback((type?: BeadType) => {
    const beadType = type ?? ADD_CYCLE[addCounter++ % ADD_CYCLE.length];
    const config = BEAD_TYPE_DEFAULTS[beadType];
    const newBead: BeadState = {
      id: `bead-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
      type: beadType,
      radius: config.radius,
      color: config.color,
    };
    setBeads((prev) => [...prev, newBead]);
  }, []);

  const removeBead = useCallback((id: BeadId) => {
    setBeads((prev) => prev.filter((b) => b.id !== id));
  }, []);

  const removeLast = useCallback(() => {
    setBeads((prev) => (prev.length > 0 ? prev.slice(0, -1) : prev));
  }, []);

  const reset = useCallback(() => {
    setBeads(DEFAULT_BEADS);
  }, []);

  return { beads, addBead, removeBead, removeLast, reset };
}

"use client";

import dynamic from "next/dynamic";
import { useBeadChain } from "@/hooks/useBeadChain";

// Dynamically import the Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Client-side wrapper that owns bead chain state and passes it to the Scene.
 * Also renders minimal overlay UI for demo purposes.
 */
export default function SceneLoader() {
  const { beads, addBead, removeLast, reset } = useBeadChain();

  return (
    <div className="relative w-screen h-screen">
      {/* 3D Canvas fills the viewport — touch-action: none prevents
          browser scroll/zoom gestures on touch devices */}
      <div className="canvas-container w-full h-full">
        <Scene beads={beads} />
      </div>

      {/* ── Overlay UI ──────────────────────────────────────────────── */}

      {/* Title */}
      <div className="absolute top-4 left-4 select-none pointer-events-none">
        <h1 className="text-lg font-semibold text-gray-700 tracking-tight">
          Bead Chain
        </h1>
        <p className="text-xs text-gray-400 mt-0.5">
          Drag beads to interact
        </p>
      </div>

      {/* Controls panel */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 rounded-full bg-white/70 backdrop-blur-md shadow-lg px-4 py-2 border border-gray-200/50">
        <span className="text-sm text-gray-500 mr-2">{beads.length} beads</span>

        <button
          onClick={() => addBead()}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition-colors cursor-pointer"
        >
          + Add
        </button>

        <button
          onClick={removeLast}
          disabled={beads.length === 0}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-rose-50 text-rose-700 hover:bg-rose-100 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
        >
          − Remove
        </button>

        <button
          onClick={reset}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-gray-50 text-gray-700 hover:bg-gray-100 transition-colors cursor-pointer"
        >
          ↺ Reset
        </button>
      </div>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { RigidBody, BallCollider, useRopeJoint } from "@react-three/rapier";
import type { RapierRigidBody } from "@react-three/rapier";
import type { BeadState } from "@/types/bead";
import { BeadRigidBody } from "./BeadRigidBody";
import { ThreadLine } from "./ThreadLine";

// ── Constants ────────────────────────────────────────────────────────────────

/** Vertical distance between consecutive bead centres (world units). */
const BEAD_SPACING = 0.8;

/**
 * Rope max-length factor relative to BEAD_SPACING.
 * < 1.0 keeps the rope slightly taut (tension).
 */
const ROPE_TAUT_FACTOR = 0.92;

/** Radius of the fixed anchor ball. */
const ANCHOR_RADIUS = 0.12;

// ── JointLink ────────────────────────────────────────────────────────────────

/**
 * Thin wrapper that calls `useRopeJoint` for a single pair of bodies.
 * MUST be a separate component because React hooks cannot be called in loops.
 */
function JointLink({
  bodyA,
  bodyB,
  length,
}: {
  bodyA: React.RefObject<RapierRigidBody | null>;
  bodyB: React.RefObject<RapierRigidBody | null>;
  length: number;
}) {
  useRopeJoint(
    bodyA as React.RefObject<RapierRigidBody>,
    bodyB as React.RefObject<RapierRigidBody>,
    [[0, 0, 0], [0, 0, 0], length],
  );
  return null;
}

// ── BeadChain ────────────────────────────────────────────────────────────────

export interface BeadChainProps {
  /** Array of bead descriptors (position is computed from index). */
  beads: BeadState[];
  /** World-space position of the fixed anchor point. */
  anchorPosition: [number, number, number];
  /** Thread colour (default: "#8B4513" — saddle brown). */
  threadColor?: string;
}

/**
 * Full physics bead chain: fixed anchor → N dynamic beads connected by rope
 * joints → MeshLine thread that follows bead positions every frame.
 */
export function BeadChain({
  beads,
  anchorPosition,
  threadColor = "#8B4513",
}: BeadChainProps) {
  const [ax, ay, az] = anchorPosition;

  // ── Stable ref for the fixed anchor ───────────────────────────────────
  const anchorRef = useMemo(
    () => ({ current: null as RapierRigidBody | null }),
    [],
  );

  // ── Pre-create a stable ref object for every bead ─────────────────────
  // useMemo keyed on array length: new refs only when count changes.
  const beadRefs = useMemo(
    () =>
      beads.map(
        () => ({ current: null as RapierRigidBody | null }),
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length],
  );

  // ── Compute initial bead positions (vertical column) ──────────────────
  const beadPositions = useMemo(
    () =>
      beads.map(
        (_, i) =>
          [ax, ay - (i + 1) * BEAD_SPACING, az] as [number, number, number],
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length, ax, ay, az],
  );

  const ropeLength = BEAD_SPACING * ROPE_TAUT_FACTOR;

  return (
    <group>
      {/* ── Fixed anchor ─────────────────────────────────────────────── */}
      <RigidBody ref={anchorRef} type="fixed" position={anchorPosition}>
        <BallCollider args={[ANCHOR_RADIUS]} />
        <mesh>
          <sphereGeometry args={[ANCHOR_RADIUS, 24, 24]} />
          <meshStandardMaterial color="#444444" roughness={0.5} metalness={0.4} />
        </mesh>
      </RigidBody>

      {/* ── Dynamic beads ───────────────────────────────────────────── */}
      {beads.map((bead, i) => (
        <BeadRigidBody
          key={bead.id}
          ref={beadRefs[i]}
          radius={bead.radius}
          color={bead.color}
          type={bead.type}
          damping={2}
          position={beadPositions[i]}
        />
      ))}

      {/* ── Rope joints ─────────────────────────────────────────────── */}
      {/* anchor → bead[0] */}
      {beads.length > 0 && (
        <JointLink
          bodyA={anchorRef}
          bodyB={beadRefs[0]}
          length={ropeLength}
        />
      )}
      {/* bead[i] → bead[i+1] */}
      {beads.slice(1).map((bead, i) => (
        <JointLink
          key={`joint-${bead.id}`}
          bodyA={beadRefs[i]}
          bodyB={beadRefs[i + 1]}
          length={ropeLength}
        />
      ))}

      {/* ── Thread line visualisation ───────────────────────────────── */}
      <ThreadLine
        anchorPosition={anchorPosition}
        anchorRef={anchorRef}
        beadRefs={beadRefs}
        beadCount={beads.length}
        color={threadColor}
      />
    </group>
  );
}

/**
 * Performance Baseline (S02/T03):
 * - Device: Galaxy S24 emulation (360×780, Playwright), Desktop Edge (1280×720)
 * - Beads: 20+
 * - FPS: 60 (mobile emulation, no CPU throttle), 60 (desktop)
 * - Mitigations applied: none (optimizations sufficient)
 * - Sphere segments: 24 (down from 32)
 * - Thread curve points: 20 (down from 32)
 * - ContactShadows resolution: 256 (down from 512)
 *
 * Note: CPU throttling (4× slowdown) is a Chrome DevTools-only feature not available
 * via Playwright. Desktop + mobile emulation at native clock both sustain 60 FPS with
 * 20+ beads, providing substantial headroom above the 30 FPS target.
 */
"use client";

import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { Physics } from "@react-three/rapier";
import {
  OrbitControls,
  Environment,
  ContactShadows,
  Stats,
} from "@react-three/drei";
import { BeadChain } from "./BeadChain";
import AdaptiveRenderer from "./AdaptiveRenderer";
import { useDragStore } from "@/lib/dragStore";
import type { BeadState } from "@/types/bead";

export interface SceneProps {
  /** Array of bead descriptors — drives chain composition. */
  beads: BeadState[];
}

/**
 * OrbitControls wrapper that reads the shared drag flag and disables
 * orbit rotation while a bead is being dragged. This prevents the scene
 * from rotating simultaneously with the bead drag gesture on touch devices.
 *
 * Uses the Zustand hook so React re-renders this component when the flag
 * changes — OrbitControls picks up the new `enabled` prop immediately.
 */
function DragAwareOrbitControls() {
  const isDragging = useDragStore((s) => s.isDragging);
  return (
    <OrbitControls
      makeDefault
      minPolarAngle={0}
      maxPolarAngle={Math.PI}
      minDistance={2}
      maxDistance={20}
      enabled={!isDragging}
    />
  );
}

/**
 * Root 3D scene: Canvas → Physics → BeadChain → ThreadLine.
 * SSR-safe (loaded via SceneLoader with dynamic ssr:false).
 */
export default function Scene({ beads }: SceneProps) {
  return (
    <Canvas
      camera={{ position: [0, 1, 7], fov: 50 }}
      shadows
      style={{ background: "linear-gradient(180deg, #f0f4f8 0%, #d9e2ec 100%)" }}
    >
      {/* Soft gradient background */}
      <color attach="background" args={["#eef2f6"]} />
      <fog attach="fog" args={["#eef2f6", 12, 22]} />

      {/* Lighting: soft studio feel */}
      <ambientLight intensity={0.3} />
      <directionalLight
        position={[5, 8, 5]}
        intensity={1}
        castShadow
        shadow-mapSize-width={1024}
        shadow-mapSize-height={1024}
      />
      {/* Fill light from opposite side for softer shadows */}
      <directionalLight position={[-3, 5, -3]} intensity={0.3} />

      {/* Adaptive rendering — must be inside Canvas for R3F context */}
      <AdaptiveRenderer />

      <Suspense fallback={null}>
        <Environment preset="studio" />

        {/* Physics world: gravity tuned for snappy feel (Vercel pattern) */}
        <Physics gravity={[0, -40, 0]}>
          <BeadChain beads={beads} anchorPosition={[0, 3, 0]} />
        </Physics>

        {/* Soft ground shadow — resolution 256 for perf (default 512) */}
        <ContactShadows
          position={[0, -3, 0]}
          opacity={0.4}
          scale={10}
          blur={2}
          far={4}
          resolution={256}
        />
      </Suspense>

      <DragAwareOrbitControls />

      {/* FPS overlay — visible in dev only */}
      <Stats />
    </Canvas>
  );
}

import { create } from "zustand";

interface DragState {
  isDragging: boolean;
  setDragging: (v: boolean) => void;
}

/**
 * Shared drag flag that bridges R3F pointer events (on meshes) and
 * OrbitControls (DOM-level). Set `true` while a bead is being dragged so
 * OrbitControls can disable itself via `enabled={!isDragging}`.
 */
export const useDragStore = create<DragState>((set) => ({
  isDragging: false,
  setDragging: (v) => set({ isDragging: v }),
}));

"use client";

import { forwardRef, useRef, useCallback } from "react";
import { RigidBody, BallCollider } from "@react-three/rapier";
import type { RapierRigidBody } from "@react-three/rapier";
import type { BeadType } from "@/types/bead";
import { useDrag } from "./DragControls";
import { BeadMaterial } from "./BeadMaterial";

export interface BeadRigidBodyProps {
  radius: number;
  color: string;
  type: BeadType;
  /** Linear and angular damping (default: 2 — stabilizes chain swing). */
  damping?: number;
  /** Sphere geometry segment count (default: 24). Lower = fewer vertices, better perf. */
  segments?: number;
  position: [number, number, number];
}

/**
 * A single physics-driven bead: RigidBody + BallCollider + visual sphere.
 * Uses forwardRef so the parent can collect the RapierRigidBody ref for joints.
 * Supports pointer-drag via the useDrag hook (kinematic position pattern).
 */
export const BeadRigidBody = forwardRef<RapierRigidBody, BeadRigidBodyProps>(
  ({ radius, color, type, damping = 2, segments = 24, position }, fwdRef) => {
    // Stable local ref for useDrag (reads .current in useFrame — needs RefObject,
    // not the polymorphic ForwardedRef which can be a callback).
    const bodyRef = useRef<RapierRigidBody>(null);

    // Merge: assign to local ref AND forwarded ref (object or callback).
    const setRefs = useCallback(
      (node: RapierRigidBody | null) => {
        bodyRef.current = node;
        if (typeof fwdRef === "function") fwdRef(node);
        else if (fwdRef) fwdRef.current = node;
      },
      [fwdRef],
    );

    const { onPointerDown, onPointerUp, onPointerOver, onPointerOut } =
      useDrag(bodyRef);

    return (
      <RigidBody
        ref={setRefs}
        colliders={false}
        angularDamping={damping}
        linearDamping={damping}
        position={position}
        ccd={false}
      >
        <BallCollider args={[radius]} />
        <mesh
          castShadow
          onPointerDown={onPointerDown}
          onPointerUp={onPointerUp}
          onPointerOver={onPointerOver}
          onPointerOut={onPointerOut}
        >
          <sphereGeometry args={[radius, segments, segments]} />
          <BeadMaterial type={type} color={color} />
        </mesh>
      </RigidBody>
    );
  }
);

BeadRigidBody.displayName = "BeadRigidBody";

"use client";

import { useRef, useCallback } from "react";
import { useFrame, useThree } from "@react-three/fiber";
import type { RapierRigidBody } from "@react-three/rapier";
import * as THREE from "three";
import { useDragStore } from "@/lib/dragStore";

// ── Types ────────────────────────────────────────────────────────────────────

interface DragState {
  /** The Rapier rigid body currently being dragged. */
  body: RapierRigidBody;
  /** World-space position of the body at the start of drag. */
  startPos: { x: number; y: number; z: number };
  /** World-space position of the body in the previous frame (for velocity). */
  prevPos: { x: number; y: number; z: number };
  /** Timestamp of the previous frame (ms, for velocity calc). */
  prevTime: number;
  /** Mouse position (NDC) at pointer-down — used as reference offset. */
  pointerStart: { x: number; y: number };
}

// ── Constants ────────────────────────────────────────────────────────────────

/** Maximum number of position history entries kept for velocity smoothing. */
const HISTORY_SIZE = 3;

// ── Reusable objects (avoid GC in useFrame) ──────────────────────────────────

const _raycaster = new THREE.Raycaster();
const _plane = new THREE.Plane();
const _intersection = new THREE.Vector3();

/**
 * Hook that provides drag event handlers for a Rapier RigidBody.
 *
 * **Pattern (Vercel badge):**
 * 1. `onPointerDown` → switch body to `kinematicPosition`, start tracking
 * 2. `useFrame` → raycast from camera through pointer onto plane at body depth,
 *    call `setNextKinematicTranslation`
 * 3. `onPointerUp` → compute velocity from recent deltas, apply `setLinvel`,
 *    switch back to `dynamic`
 *
 * @param bodyRef — React ref holding the RapierRigidBody (typically from
 *                  `useForwardedRef` or `useRef`)
 * @returns Object with `onPointerDown`, `onPointerUp`, `onPointerOver`,
 *          `onPointerOut` handlers to spread onto a `<mesh>`
 */
export function useDrag(bodyRef: React.RefObject<RapierRigidBody | null>) {
  const { camera, pointer, gl } = useThree();

  // Mutable state that survives across frames without triggering re-renders
  const dragRef = useRef<DragState | null>(null);

  // Position history ring buffer for velocity smoothing
  const historyRef = useRef<
    { pos: THREE.Vector3; time: number }[]
  >([]);
  const historyIndexRef = useRef(0);

  // ── Pointer Down: start dragging ──────────────────────────────────────
  const onPointerDown = useCallback(
    (e: { stopPropagation: () => void }) => {
      const body = bodyRef.current;
      if (!body) return;

      e.stopPropagation();

      // Signal OrbitControls to disable while we drag a bead
      useDragStore.getState().setDragging(true);

      // Switch to kinematic — physics engine won't apply forces to this body
      body.setBodyType({ type: "kinematicPosition" } as never, true);
      body.wakeUp();

      const pos = body.translation();
      const now = performance.now();

      dragRef.current = {
        body,
        startPos: { x: pos.x, y: pos.y, z: pos.z },
        prevPos: { x: pos.x, y: pos.y, z: pos.z },
        prevTime: now,
        pointerStart: { x: pointer.x, y: pointer.y },
      };

      // Reset history
      historyRef.current = [];
      historyIndexRef.current = 0;

      // Change cursor
      gl.domElement.style.cursor = "grabbing";
    },
    [bodyRef, pointer, gl],
  );

  // ── Pointer Up: stop dragging, apply velocity ─────────────────────────
  const onPointerUp = useCallback(() => {
    const drag = dragRef.current;
    if (!drag) return;

    const body = drag.body;
    const history = historyRef.current;

    // Compute average velocity from the last few frames
    if (history.length >= 2) {
      const recent = history.slice(-HISTORY_SIZE);
      const first = recent[0];
      const last = recent[recent.length - 1];
      const dt = (last.time - first.time) / 1000; // seconds

      if (dt > 0.001) {
        const vx = (last.pos.x - first.pos.x) / dt;
        const vy = (last.pos.y - first.pos.y) / dt;
        const vz = (last.pos.z - first.pos.z) / dt;

        // Clamp velocity to prevent crazy throws
        const maxVel = 30;
        const clamp = (v: number) => Math.max(-maxVel, Math.min(maxVel, v));

        body.setLinvel({ x: clamp(vx), y: clamp(vy), z: clamp(vz) }, true);
      }
    }

    // Give a small angular velocity for natural spin feel
    body.setAngvel({ x: 0.5, y: 0, z: 0.2 }, true);

    // Switch back to dynamic
    body.setBodyType({ type: "dynamic" } as never, true);
    body.wakeUp();

    dragRef.current = null;
    historyRef.current = [];
    historyIndexRef.current = 0;

    // Re-enable OrbitControls now that bead drag is finished
    useDragStore.getState().setDragging(false);

    gl.domElement.style.cursor = "auto";
  }, [gl]);

  // ── Cursor handlers ───────────────────────────────────────────────────
  const onPointerOver = useCallback(() => {
    if (!dragRef.current) {
      gl.domElement.style.cursor = "grab";
    }
  }, [gl]);

  const onPointerOut = useCallback(() => {
    if (!dragRef.current) {
      gl.domElement.style.cursor = "auto";
    }
  }, [gl]);

  // ── Per-frame: move kinematic body to follow pointer ──────────────────
  useFrame(() => {
    const drag = dragRef.current;
    if (!drag || !bodyRef.current) return;

    // Construct a plane at the body's current depth, facing the camera
    const bodyPos = drag.body.translation();
    _plane.setFromNormalAndCoplanarPoint(
      camera.getWorldDirection(new THREE.Vector3()).negate(),
      new THREE.Vector3(bodyPos.x, bodyPos.y, bodyPos.z),
    );

    // Raycast from camera through NDC pointer position
    _raycaster.setFromCamera(new THREE.Vector2(pointer.x, pointer.y), camera);

    if (_raycaster.ray.intersectPlane(_plane, _intersection)) {
      const x = _intersection.x;
      const y = _intersection.y;
      const z = _intersection.z;

      drag.body.setNextKinematicTranslation({ x, y, z });

      // Record position for velocity computation
      const now = performance.now();
      const history = historyRef.current;
      history.push({
        pos: new THREE.Vector3(x, y, z),
        time: now,
      });

      // Keep only recent history to bound memory
      if (history.length > HISTORY_SIZE + 1) {
        history.shift();
      }
    }
  });

  return {
    onPointerDown,
    onPointerUp,
    onPointerOver,
    onPointerOut,
    isDragging: dragRef,
  };
}

